// Tier-3 capture-time eligibility classifier.
//
// Decides whether a captured screen is in the reconstruction-eligible class
// (FINDINGS / handoff §4): same-origin app screens whose data lives in
// HOMOGENEOUS REPEATED STRUCTURES (tables / aria-rows / lists / forms), standard
// DOM/CSS, no dominant raster/canvas surface, no KPI/metric grid. Motion-anchor
// stability (semantic vs CSS-in-JS hashed) gates ANIMATION, not reconstruction.
//
// Two halves, deliberately split:
//   - `collectSignalsInPage()` runs in the browser and returns raw JSON signals.
//   - `classify(signals)` is a PURE decision (unit-testable without a browser),
//     fail-safe biased to "video" on uncertainty (a wrong "video" costs nothing;
//     a wrong "reconstruction" ships a broken demo — FINDINGS' CHROME bias).

export type RepeatedGroup = {
  kind: "table" | "aria-rows" | "list" | "cards";
  count: number;
  selector: string;
};

export type EligibilitySignals = {
  vw: number;
  vh: number;
  repeated: RepeatedGroup[];
  maxRepeat: number;
  formFields: number;
  rasterHeroFraction: number;
  canvasFraction: number;
  kpiCards: number;
  textChars: number;
  anchorStableRatio: number;
  sampleStableAnchors: string[];
  sampleHashedAnchors: string[];
};

export type Classification = {
  /** In the reconstruction-eligible class. */
  eligible: boolean;
  /** Authored motion can bind to stable anchors (rrweb replay does not need this). */
  animatable: boolean;
  reasons: string[];
  signals: EligibilitySignals;
};

// Thresholds (tunable; see PHASE_3_REPORT for rationale).
export const MIN_REPEAT = 3; // a homogeneous group needs >= 3 members
export const HERO_FRACTION = 0.35; // raster/img covering > this share near top => marketing hero
export const CANVAS_FRACTION = 0.35; // canvas covering > this share => data-as-raster
export const ANCHOR_STABLE_MIN = 0.6; // >= this share of anchors stable => animatable

/* istanbul ignore next -- runs in the browser, exercised via Playwright */
export function collectSignalsInPage(): EligibilitySignals {
  // Self-contained for page.evaluate: no module-scope refs (constants inlined).
  const MIN_REPEAT = 3;
  const vw = window.innerWidth;
  const vh = window.innerHeight;
  const viewportArea = Math.max(1, vw * vh);
  const area = (el: Element): number => {
    const r = el.getBoundingClientRect();
    return Math.max(0, r.width) * Math.max(0, r.height);
  };
  const visible = (el: Element): boolean => {
    const r = el.getBoundingClientRect();
    if (r.width < 2 || r.height < 2) return false;
    const cs = getComputedStyle(el);
    return cs.visibility !== "hidden" && cs.display !== "none" && cs.opacity !== "0";
  };

  // ---- homogeneous repeated structures -------------------------------------
  const repeated: RepeatedGroup[] = [];
  const cssPath = (el: Element): string => {
    if (el.id) return `#${el.id}`;
    const tag = el.tagName.toLowerCase();
    const cls = (el.getAttribute("class") || "").trim().split(/\s+/).filter(Boolean).slice(0, 1);
    return cls.length ? `${tag}.${cls[0]}` : tag;
  };

  for (const table of Array.from(document.querySelectorAll("table"))) {
    if (!visible(table)) continue;
    const rows = table.querySelectorAll("tbody tr, tr").length;
    if (rows >= 2) repeated.push({ kind: "table", count: rows, selector: cssPath(table) });
  }
  for (const list of Array.from(document.querySelectorAll("ul,ol"))) {
    if (!visible(list)) continue;
    const items = Array.from(list.children).filter((c) => c.tagName.toLowerCase() === "li" && visible(c)).length;
    if (items >= MIN_REPEAT) repeated.push({ kind: "list", count: items, selector: cssPath(list) });
  }
  // aria rows/grid
  const ariaRows = Array.from(document.querySelectorAll('[role="row"]')).filter(visible).length;
  if (ariaRows >= MIN_REPEAT) repeated.push({ kind: "aria-rows", count: ariaRows, selector: '[role="row"]' });

  // generic card grids: a parent whose direct element children are >= MIN_REPEAT
  // siblings of the same tag with similar child-count and similar width.
  let kpiCards = 0;
  const numericDominant = (el: Element): boolean => {
    const t = (el.textContent || "").trim();
    if (!t || t.length > 24) return false;
    const digits = (t.match(/[0-9]/g) || []).length;
    return digits >= 1 && digits / t.replace(/\s/g, "").length >= 0.4;
  };
  const seenParents = new Set<Element>();
  for (const el of Array.from(document.querySelectorAll("*"))) {
    const kids = Array.from(el.children).filter(visible);
    if (kids.length < MIN_REPEAT) continue;
    if (seenParents.has(el)) continue;
    const tag0 = kids[0]!.tagName.toLowerCase();
    if (tag0 === "li" || tag0 === "tr" || tag0 === "option") continue; // covered above
    const sameTag = kids.filter((k) => k.tagName.toLowerCase() === tag0).length;
    if (sameTag < kids.length * 0.8) continue;
    if (["p", "br", "span", "a", "img"].includes(tag0)) continue; // prose/inline/nav, not data cards
    const structuredKids = kids.filter((k) => k.children.length >= 1).length;
    if (structuredKids < kids.length * 0.8) continue; // a data card has internal structure
    const widths = kids.map((k) => k.getBoundingClientRect().width);
    const wMin = Math.min(...widths);
    const wMax = Math.max(...widths);
    if (wMax <= 0 || wMin / wMax < 0.7) continue; // similar widths => a grid/list of cards
    seenParents.add(el);
    repeated.push({ kind: "cards", count: kids.length, selector: cssPath(el) });
    // KPI heuristic: each card dominated by a single numeric value (label+value).
    const numericKids = kids.filter((k) => {
      const big = Array.from(k.querySelectorAll("*")).some(numericDominant) || numericDominant(k);
      return big;
    }).length;
    if (numericKids >= kids.length * 0.6) kpiCards = Math.max(kpiCards, kids.length);
  }

  const maxRepeat = repeated.reduce((m, g) => Math.max(m, g.count), 0);

  // ---- forms ---------------------------------------------------------------
  const formFields = Array.from(document.querySelectorAll("input,select,textarea")).filter(visible).length;

  // ---- raster hero / canvas ------------------------------------------------
  let rasterHeroFraction = 0;
  for (const img of Array.from(document.querySelectorAll("img"))) {
    if (!visible(img)) continue;
    const r = img.getBoundingClientRect();
    if (r.top > vh * 0.8) continue; // must be near the top to count as a hero
    rasterHeroFraction = Math.max(rasterHeroFraction, area(img) / viewportArea);
  }
  for (const el of Array.from(document.querySelectorAll("*"))) {
    const bg = getComputedStyle(el).backgroundImage;
    if (!bg || !bg.includes("url(")) continue;
    if (!visible(el)) continue;
    const r = el.getBoundingClientRect();
    if (r.top > vh * 0.8) continue;
    rasterHeroFraction = Math.max(rasterHeroFraction, area(el) / viewportArea);
  }
  let canvasFraction = 0;
  for (const c of Array.from(document.querySelectorAll("canvas"))) {
    if (!visible(c)) continue;
    canvasFraction = Math.max(canvasFraction, area(c) / viewportArea);
  }

  // ---- anchor stability ----------------------------------------------------
  const SEMANTIC = new Set([
    "table", "thead", "tbody", "tr", "td", "th", "ul", "ol", "li", "nav", "header",
    "main", "footer", "section", "article", "aside", "form", "label", "button",
    "h1", "h2", "h3", "h4", "h5", "h6", "input", "select", "textarea",
  ]);
  const isHashedToken = (t: string): boolean =>
    /^css-[a-z0-9]{4,}$/i.test(t) ||
    /^sc-[a-z0-9]+$/i.test(t) ||
    /^[A-Za-z][\w]*__[A-Za-z0-9]{4,}$/.test(t) || // CSS-modules Foo__hash
    (/^[a-z0-9]{7,}$/i.test(t) && /[0-9]/.test(t) && /[a-z]/i.test(t)); // random alnum
  const stableEl = (el: Element): boolean => {
    if (el.id) return true;
    if (el.hasAttribute("role")) return true;
    if (SEMANTIC.has(el.tagName.toLowerCase())) return true;
    if (el.tagName.toLowerCase() === "a" && el.hasAttribute("href")) return true;
    for (const a of Array.from(el.attributes)) if (a.name.startsWith("data-")) return true;
    return false;
  };
  let stable = 0;
  let hashedOnly = 0;
  const sampleStableAnchors: string[] = [];
  const sampleHashedAnchors: string[] = [];
  const meaningful = Array.from(document.querySelectorAll("a,button,input,select,textarea,td,th,li,[role],h1,h2,h3,p,span,div"))
    .filter(visible)
    .filter((el) => (el.textContent || "").trim().length > 0 || ["a", "button", "input"].includes(el.tagName.toLowerCase()));
  for (const el of meaningful.slice(0, 400)) {
    if (stableEl(el)) {
      stable += 1;
      if (sampleStableAnchors.length < 8) sampleStableAnchors.push(cssPath(el));
    } else {
      const tokens = (el.getAttribute("class") || "").trim().split(/\s+/).filter(Boolean);
      if (tokens.some(isHashedToken)) {
        hashedOnly += 1;
        if (sampleHashedAnchors.length < 8) sampleHashedAnchors.push(tokens.find(isHashedToken)!);
      } else {
        stable += 1; // plain/utility classes are re-locatable enough
      }
    }
  }
  const anchorStableRatio = stable + hashedOnly === 0 ? 1 : stable / (stable + hashedOnly);

  return {
    vw, vh, repeated, maxRepeat, formFields,
    rasterHeroFraction: round(rasterHeroFraction),
    canvasFraction: round(canvasFraction),
    kpiCards,
    textChars: (document.body?.innerText || "").trim().length,
    anchorStableRatio: round(anchorStableRatio),
    sampleStableAnchors, sampleHashedAnchors,
  };

  function round(v: number): number {
    return Math.round(v * 1000) / 1000;
  }
}

/** Pure, fail-safe decision over the signals. */
export function classify(signals: EligibilitySignals): Classification {
  const reasons: string[] = [];
  const hasTableOrAria = signals.repeated.some((g) => g.kind === "table" || g.kind === "aria-rows");
  const hasHomogeneous = signals.maxRepeat >= MIN_REPEAT || hasTableOrAria;
  const hasForm = signals.formFields >= 3;
  const heroHit = signals.rasterHeroFraction > HERO_FRACTION;
  const canvasHit = signals.canvasFraction > CANVAS_FRACTION;
  const kpiHit = signals.kpiCards >= MIN_REPEAT;

  if (hasHomogeneous) reasons.push(`homogeneous repeated structure (max ${signals.maxRepeat}, kinds: ${[...new Set(signals.repeated.map((r) => r.kind))].join("/") || "none"})`);
  if (hasForm) reasons.push(`form with ${signals.formFields} fields`);
  if (heroHit) reasons.push(`raster hero covers ${(signals.rasterHeroFraction * 100).toFixed(0)}% near top (ineligible)`);
  if (canvasHit) reasons.push(`dominant canvas covers ${(signals.canvasFraction * 100).toFixed(0)}% (data-as-raster, ineligible)`);
  // KPI/numeric grids are NOT structurally vetoed: a DOM stat grid reconstructs
  // faithfully, and idealization (the lab's reason to reject KPI) is deferred —
  // customers seed clean data. The calibrated quality check is the real backstop.
  // (A canvas-backed chart is still rejected via the dominant-canvas veto.)
  if (kpiHit) reasons.push(`numeric/metric grid (${signals.kpiCards} cards) — DOM-reconstructable; idealization deferred (quality check is the gate)`);

  const structural = hasHomogeneous || hasForm;
  const eligible = structural && !heroHit && !canvasHit;

  if (!structural) reasons.push("no homogeneous data structure detected (fail-safe → video)");

  const animatable = signals.anchorStableRatio >= ANCHOR_STABLE_MIN;
  reasons.push(`anchor stability ${(signals.anchorStableRatio * 100).toFixed(0)}% → motion ${animatable ? "bindable" : "NOT bindable (replay-only)"}`);

  return { eligible, animatable, reasons, signals };
}
