// Capture-time routing: reconstruction vs today's video path.
//
// Fail-safe asymmetry (FINDINGS CHROME bias): a wrong "video" call costs nothing
// (the screen just keeps using today's pipeline); a wrong "reconstruction" call
// ships a broken demo. So anything not clearly eligible AND clearly passing the
// calibrated quality bar routes to video.

import type { Classification } from "./classify.js";

export type Route = "reconstruction" | "video";

export type QualitySummary = { pass: boolean; pixelDiffPct: number; ssim: number };

export type RouteDecision = {
  route: Route;
  reason: string;
  eligible: boolean;
  /** null when the quality check was not run (e.g. ineligible short-circuit). */
  qualityPass: boolean | null;
};

export function decideRoute(
  classification: Classification,
  quality?: QualitySummary | null,
): RouteDecision {
  if (!classification.eligible) {
    const reason =
      classification.reasons.find((r) => /ineligible|fail-safe/.test(r)) ??
      "not in the reconstruction-eligible class";
    return { route: "video", reason, eligible: false, qualityPass: quality?.pass ?? null };
  }
  if (quality && !quality.pass) {
    return {
      route: "video",
      reason: `reconstruction missed the calibrated bar (pixelDiff ${quality.pixelDiffPct}%, ssim ${quality.ssim})`,
      eligible: true,
      qualityPass: false,
    };
  }
  return {
    route: "reconstruction",
    reason: classification.reasons[0] ?? "eligible",
    eligible: true,
    qualityPass: quality?.pass ?? null,
  };
}
