// Phase 4.6 · S1 — the clean-data GUARD.
//
// A pure check over a captured screen's HTML: is its data marketing-grade, or does
// it still carry empty states, placeholder/test data, or leaked PII? The plan-aligned
// "idealized data" path is to capture a deliberately SEEDED clean workspace — this
// guard does NOT invent clean data, it DETECTS dirty data so the pipeline / loop can
// refuse to ship a messy clip. Conservative + fail-safe: it errs toward "not clean".
//
// Pure (no DOM, no I/O): same HTML → same result. Text is extracted by stripping
// script/style + tags so inlined data-URIs/fonts can't trip the patterns.

export type CleanDataHit = {
  /** Category: "empty-state" | "placeholder" | "pii-email" | "pii-phone" | custom. */
  kind: string;
  /** The matched snippet (trimmed), for the skip-reason log. */
  sample: string;
};

export type CleanDataResult = {
  clean: boolean;
  reasons: string[];
  hits: CleanDataHit[];
};

export type CleanDataConfig = {
  /** Extra deny patterns (regex source + kind label + optional flags). */
  deny?: { pattern: string; kind: string; flags?: string }[];
  /** Phrases that indicate an empty/placeholder state (case-insensitive substring). */
  emptyStatePhrases?: string[];
  /** Substrings that SUPPRESS a hit when they contain the match (legit product copy). */
  allow?: string[];
  /** Tolerated count of email-like strings before flagging. Default 0. */
  maxEmails?: number;
  /** Tolerated count of phone-like strings before flagging. Default 0. */
  maxPhones?: number;
  /** Run PII (email/phone) checks. Default true. Disable for screens that legitimately show contacts. */
  pii?: boolean;
};

const DEFAULT_EMPTY_PHRASES = [
  "no data",
  "no results",
  "no items",
  "no activity",
  "nothing here",
  "nothing to show",
  "you don't have any",
  "you have no",
  "get started by",
  "create your first",
  "0 results",
  "no records",
  "empty",
  "coming soon",
  "loading…",
  "loading...",
];

// Placeholder / test-data patterns. Anchored / multi-token to avoid false positives
// on legit words ("latest", "contest", "example screen" in real copy).
const DEFAULT_DENY: { pattern: string; kind: string; flags?: string }[] = [
  { pattern: "lorem ipsum", kind: "placeholder" },
  { pattern: "\\bdolor sit amet\\b", kind: "placeholder" },
  { pattern: "\\basdf+\\b", kind: "placeholder" },
  { pattern: "\\bqwerty\\b", kind: "placeholder" },
  { pattern: "\\bfoo ?bar\\b", kind: "placeholder" },
  { pattern: "\\bplaceholder\\b", kind: "placeholder" },
  { pattern: "\\b(dummy|sample|test) (data|text|user|value|content)\\b", kind: "placeholder" },
  { pattern: "@(example|test)\\.(com|org)\\b", kind: "placeholder" },
  { pattern: "\\bxxx+\\b", kind: "placeholder" },
  { pattern: "\\btodo\\b", kind: "placeholder" },
];

// PII patterns. example/test domains are caught as placeholders, not PII.
const EMAIL_RE = /[a-z0-9._%+-]+@(?!example\.|test\.)[a-z0-9.-]+\.[a-z]{2,}/gi;
const PHONE_RE = /(?:\+?\d[\d\s().-]{8,}\d)/g;

/** Strip script/style + tags, decode the common entities, collapse whitespace. */
export function extractVisibleText(html: string): string {
  return html
    .replace(/<script[\s\S]*?<\/script>/gi, " ")
    .replace(/<style[\s\S]*?<\/style>/gi, " ")
    .replace(/<!--[\s\S]*?-->/g, " ")
    .replace(/<[^>]+>/g, " ")
    .replace(/&nbsp;/gi, " ")
    .replace(/&amp;/gi, "&")
    .replace(/&lt;/gi, "<")
    .replace(/&gt;/gi, ">")
    .replace(/&quot;/gi, '"')
    .replace(/&#0?39;|&apos;/gi, "'")
    .replace(/&[a-z]+;/gi, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function allowed(sample: string, allow: string[]): boolean {
  const s = sample.toLowerCase();
  return allow.some((a) => s.includes(a.toLowerCase()));
}

/**
 * Check whether a captured screen's data is marketing-grade. Returns every hit so
 * the caller can log specific skip reasons. `clean` is true iff there are no hits.
 */
export function checkCleanData(
  input: { html: string } | string,
  config: CleanDataConfig = {},
): CleanDataResult {
  const html = typeof input === "string" ? input : input.html;
  const text = extractVisibleText(html);
  const lower = text.toLowerCase();
  const allow = config.allow ?? [];
  const hits: CleanDataHit[] = [];

  const emptyPhrases = config.emptyStatePhrases ?? DEFAULT_EMPTY_PHRASES;
  for (const phrase of emptyPhrases) {
    const idx = lower.indexOf(phrase.toLowerCase());
    if (idx >= 0) {
      const sample = text.slice(Math.max(0, idx - 12), idx + phrase.length + 12).trim();
      if (!allowed(sample, allow)) hits.push({ kind: "empty-state", sample });
    }
  }

  for (const rule of [...DEFAULT_DENY, ...(config.deny ?? [])]) {
    const re = new RegExp(rule.pattern, rule.flags ?? "gi");
    const m = re.exec(text);
    if (m && !allowed(m[0], allow)) hits.push({ kind: rule.kind, sample: m[0].trim() });
  }

  if (config.pii !== false) {
    const emails = (text.match(EMAIL_RE) ?? []).filter((e) => !allowed(e, allow));
    if (emails.length > (config.maxEmails ?? 0)) {
      hits.push({ kind: "pii-email", sample: `${emails.length} email(s) e.g. ${emails[0]}` });
    }
    const phones = (text.match(PHONE_RE) ?? []).map((p) => p.trim()).filter((p) => !allowed(p, allow));
    if (phones.length > (config.maxPhones ?? 0)) {
      hits.push({ kind: "pii-phone", sample: `${phones.length} phone(s) e.g. ${phones[0]}` });
    }
  }

  const reasons = Array.from(new Set(hits.map((h) => h.kind))).map((kind) => {
    const samples = hits.filter((h) => h.kind === kind).map((h) => h.sample);
    return `${kind}: ${samples.slice(0, 3).join(" | ")}`;
  });

  return { clean: hits.length === 0, reasons, hits };
}
