// Shared Node-side resource transport for Tier-3 capture.
//
// The in-page `fetch()` the serializer used to rely on runs inside the browser's
// CORS sandbox: cross-origin images, 302-redirected signed URLs (e.g. an
// /api/.../versions route that bounces to R2/CDN), and no-CORS responses all
// fail there, and a canvas read-back taints. `page.request.get` instead drives
// the browser's OWN network stack from Node — it is NOT subject to CORS, follows
// redirects, and shares the context's cookies — so it resolves the resources the
// page actually rendered. This is the mechanism m4 already used; m7 now shares it,
// which removes the whole class of "image wouldn't inline" capture failures.

import type { Page } from "playwright-core";

/** Cap a single resource so one giant asset can't bloat the artifact. */
const MAX_RESOURCE_BYTES = 4_000_000;

/**
 * Fetch each URL via the browser's request context and return url → data-URI.
 * URLs that fail (network error, !ok, oversize) are simply omitted from the map;
 * callers decide the fallback (leave the URL, or rasterize a sidecar).
 */
export async function resolveResourceUris(page: Page, urls: Iterable<string>): Promise<Record<string, string>> {
  const unique = [...new Set([...urls])].filter((u) => u && !u.startsWith("data:"));
  const out: Record<string, string> = {};
  await Promise.all(
    unique.map(async (u) => {
      try {
        const resp = await page.request.get(u, { timeout: 8000 });
        if (!resp.ok()) return;
        const buf = await resp.body();
        if (buf.length > MAX_RESOURCE_BYTES) return;
        const ct = resp.headers()["content-type"] || "application/octet-stream";
        out[u] = `data:${ct.split(";")[0]};base64,${buf.toString("base64")}`;
      } catch {
        /* unresolved — omitted */
      }
    }),
  );
  return out;
}

/** Replace every resolved URL with its data-URI throughout an HTML string. */
export function inlineResolvedUris(html: string, dataUris: Record<string, string>): string {
  let out = html;
  for (const [u, d] of Object.entries(dataUris)) {
    // Both attribute form (src="…") and CSS url(…) forms collapse to a plain
    // substring replace of the absolute URL. `outerHTML`/inline-style serialization
    // HTML-escapes `&` in attribute values, so also replace the &amp; variant
    // (e.g. a signed URL with `?a=1&b=2`) — otherwise the swap silently misses.
    out = out.split(u).join(d);
    const escaped = u.replace(/&/g, "&amp;");
    if (escaped !== u) out = out.split(escaped).join(d);
  }
  return out;
}
