// Tier-3 eligibility gate: classify a captured screen and route it to the
// reconstruction pipeline or today's video pipeline.

import type { Page } from "playwright-core";

import {
  captureDom,
  launchBrowser,
  openPage,
  navigate,
  settle,
  remountScreenshot,
  DEFAULT_CAPTURE_SETTINGS,
  type CaptureSettings,
  type CaptureSnapshot,
  type CaptureStorageState,
} from "../capture/index.js";
import { decodePng, diffImages } from "../verify/diff.js";
import { verdict } from "../verify/thresholds.js";
import { classify, collectSignalsInPage, type Classification } from "./classify.js";
import { decideRoute, type RouteDecision } from "./route.js";

export {
  classify,
  collectSignalsInPage,
  MIN_REPEAT,
  HERO_FRACTION,
  CANVAS_FRACTION,
  ANCHOR_STABLE_MIN,
} from "./classify.js";
export type { Classification, EligibilitySignals, RepeatedGroup } from "./classify.js";
export { decideRoute } from "./route.js";
export type { Route, RouteDecision, QualitySummary } from "./route.js";
// Phase 4.6 — the clean-data guard (publish-worthiness of a captured screen's data).
export { checkCleanData, extractVisibleText } from "../quality/clean-data.js";
export type { CleanDataResult, CleanDataHit, CleanDataConfig } from "../quality/clean-data.js";

/** Classify a live, navigated, settled page. */
export async function classifyPage(page: Page): Promise<Classification> {
  const signals = await page.evaluate(collectSignalsInPage);
  return classify(signals);
}

export type ScreenEvaluation = {
  classification: Classification;
  decision: RouteDecision;
  /** Quality is only measured when the screen is structurally eligible. */
  quality: { pass: boolean; pixelDiffPct: number; ssim: number } | null;
  livePng: Buffer;
  /** Only produced when eligible (reconstruction attempted). */
  remountPng: Buffer | null;
  snapshot: CaptureSnapshot | null;
};

/**
 * The capture-time gate on an ALREADY navigated + settled page: screenshot,
 * classify, and if (and only if) structurally eligible, reconstruct + remount +
 * run the calibrated quality check, then route. Use this when the caller owns the
 * browser/page lifecycle — e.g. authenticated `/app` screens that need cookies +
 * an init script before navigation (the auto-update loop over real dashboards).
 * `evaluateUrl` is the unauthenticated convenience wrapper around this.
 */
export async function evaluatePage(
  page: Page,
  opts: { settings?: CaptureSettings; csp?: string | null } = {},
): Promise<ScreenEvaluation> {
  const settings = opts.settings ?? DEFAULT_CAPTURE_SETTINGS;
  const livePng = await page.screenshot({ type: "png" });
  const classification = await classifyPage(page);
  let snapshot: CaptureSnapshot | null = null;
  if (classification.eligible) {
    snapshot = await captureDom(page, { csp: opts.csp ?? null });
  }

  let quality: ScreenEvaluation["quality"] = null;
  let remountPng: Buffer | null = null;
  if (snapshot) {
    remountPng = await remountScreenshot(snapshot.html, snapshot.scrolls, settings);
    const diff = diffImages(decodePng(remountPng), decodePng(livePng));
    const v = verdict(diff);
    quality = { pass: v.pass, pixelDiffPct: diff.pixelDiffPct, ssim: diff.ssim };
  }

  const decision = decideRoute(classification, quality);
  return { classification, decision, quality, livePng, remountPng, snapshot };
}

/**
 * End-to-end capture-time gate in ONE navigation: classify, and if (and only if)
 * structurally eligible, reconstruct + remount + run the calibrated quality check,
 * then route. Ineligible screens short-circuit BEFORE any reconstruction work —
 * the video path does no extra rendering (additive, no regression).
 */
export async function evaluateUrl(
  url: string,
  opts: { settings?: CaptureSettings; csp?: string | null; storageState?: CaptureStorageState } = {},
): Promise<ScreenEvaluation> {
  const settings = opts.settings ?? DEFAULT_CAPTURE_SETTINGS;
  const browser = await launchBrowser();
  try {
    const page = await openPage(browser, settings, opts.storageState);
    const resp = await navigate(page, url);
    await settle(page);
    const csp = opts.csp ?? resp?.headers()["content-security-policy"] ?? null;
    return await evaluatePage(page, { settings, csp });
  } finally {
    await browser.close();
  }
}
