// Tier-3 DOM-capture engine: capture a live screen as a self-contained DOM
// reconstruction artifact that re-mounts to a pixel-indistinguishable result.
//
// Stack: m7 hybrid primary, m4 CDP DOMSnapshot fallback (closed Shadow DOM / CSP).
// Clean reimplementation of the fidelity-lab techniques — no lab code is imported.

import { mkdir, writeFile } from "node:fs/promises";
import { dirname } from "node:path";

import type { Page } from "playwright-core";

import { snapshotM4 } from "./m4-domsnapshot.js";
import { snapshotM7 } from "./m7-hybrid.js";
import { detectClosedShadowInPage } from "./serialize.js";
import {
  DEFAULT_CAPTURE_SETTINGS,
  launchBrowser,
  liveScreenshot,
  openPage,
  remountScreenshot,
  renderArtifactOffline,
  settle,
  navigate,
  type CaptureSettings,
  type CaptureStorageState,
} from "./remount.js";
import type { CaptureMethod, CaptureSnapshot } from "./types.js";

export type { CaptureMethod, CaptureSnapshot, SurfaceMeta } from "./types.js";
export type { CaptureSettings, CaptureStorageState } from "./remount.js";
export {
  DEFAULT_CAPTURE_SETTINGS,
  liveScreenshot,
  remountScreenshot,
  renderArtifactOffline,
  launchBrowser,
  openPage,
  settle,
  navigate,
} from "./remount.js";

/**
 * Decide whether to fall back from m7 (primary) to m4. m7's in-page walk cannot
 * see CLOSED shadow DOM, and a restrictive CSP blocks its in-page asset/font
 * fetches; m4 (CDP) sees Chromium's flattened render tree and transports
 * resources out-of-page, so it survives both.
 */
export function shouldFallbackToM4(signals: { closedShadow: boolean; csp?: string | null }): boolean {
  if (signals.closedShadow) return true;
  const csp = (signals.csp ?? "").toLowerCase();
  if (!csp) return false;
  // A connect-src / default-src that bars our cross-origin in-page fetch (no
  // scheme/host allowance) breaks m7's font+asset inlining → prefer m4.
  if (/(?:default-src|connect-src)\s+'none'/.test(csp)) return true;
  if (/connect-src\s+'self'(?:[^;]*)?(?:;|$)/.test(csp) && !/connect-src[^;]*https?:/.test(csp)) return true;
  return false;
}

export type CaptureDomOptions = {
  /** Force a specific method (skips detection). Used by tests to prove fallback. */
  forceMethod?: CaptureMethod;
  /** CSP header from the page response, for fallback detection. */
  csp?: string | null;
};

/** Capture a self-contained reconstruction from a live, navigated, settled page. */
export async function captureDom(page: Page, opts: CaptureDomOptions = {}): Promise<CaptureSnapshot> {
  let method: CaptureMethod;
  if (opts.forceMethod) {
    method = opts.forceMethod;
  } else {
    const closedShadow = await page.evaluate(detectClosedShadowInPage).catch(() => false);
    method = shouldFallbackToM4({ closedShadow, csp: opts.csp }) ? "m4" : "m7";
  }
  return method === "m4" ? snapshotM4(page) : snapshotM7(page);
}

export type CaptureArtifactPaths = { html: string; meta: string };

/** Write the artifact + sidecar metadata. Returns the written paths. */
export async function writeArtifact(snapshot: CaptureSnapshot, basePath: string): Promise<CaptureArtifactPaths> {
  await mkdir(dirname(basePath), { recursive: true });
  const html = `${basePath}.dom.html`;
  const meta = `${basePath}.dom.meta.json`;
  await writeFile(html, snapshot.html, "utf8");
  await writeFile(
    meta,
    JSON.stringify(
      { method: snapshot.method, scrolls: snapshot.scrolls, surfaces: snapshot.surfaces, notes: snapshot.notes },
      null,
      2,
    ),
    "utf8",
  );
  return { html, meta };
}

export type CaptureUrlResult = {
  snapshot: CaptureSnapshot;
  method: CaptureMethod;
  livePng: Buffer;
  remountPng: Buffer;
};

export type CaptureUrlOptions = CaptureDomOptions & {
  settings?: CaptureSettings;
  storageState?: CaptureStorageState;
};

/**
 * End-to-end: navigate to `url`, take a deterministic live screenshot, capture a
 * DOM artifact (auto-selecting m7/m4), and remount it to a screenshot at the same
 * settings — everything the calibrated quality gate needs.
 */
export async function captureUrl(url: string, opts: CaptureUrlOptions = {}): Promise<CaptureUrlResult> {
  const settings = opts.settings ?? DEFAULT_CAPTURE_SETTINGS;
  const browser = await launchBrowser();
  let snapshot: CaptureSnapshot;
  let method: CaptureMethod;
  let livePng: Buffer;
  try {
    const page = await openPage(browser, settings, opts.storageState);
    const resp = await navigate(page, url);
    await settle(page);
    livePng = await page.screenshot({ type: "png" });
    const csp = opts.csp ?? resp?.headers()["content-security-policy"] ?? null;
    snapshot = await captureDom(page, { forceMethod: opts.forceMethod, csp });
    method = snapshot.method;
  } finally {
    await browser.close();
  }
  const remountPng = await remountScreenshot(snapshot.html, snapshot.scrolls, settings);
  return { snapshot, method, livePng, remountPng };
}
