// Calibrated image diff for the Tier-3 verification harness (the "evaluator").
//
// Clean reimplementation of the fidelity-lab metric (fidelity-lab/harness/diff.mjs):
// pixelmatch pixel-diff% + ssim.js SSIM, using the SAME library parameters so the
// numbers reproduce the lab's calibration set. We intentionally require equal
// dimensions here (our renders are size-controlled) instead of pulling in sharp.
//
// Provenance of the calibrated thresholds these numbers are judged against:
// single-rater (jake), provisional — see thresholds.ts and docs/tier3/00-AUDIT.md §5.

import { readFile, mkdir, writeFile } from "node:fs/promises";
import { dirname } from "node:path";

import pixelmatch from "pixelmatch";
import { PNG } from "pngjs";
import { ssim as ssimFn } from "ssim.js";

// pixelmatch perceptual threshold (0..1). 0.1 is the library default and the lab's
// value — "differing pixel" means a visibly different pixel. Keep in lockstep with
// the lab so calibration numbers reproduce.
export const PIXELMATCH_THRESHOLD = 0.1;

export type RgbaImage = {
  data: Uint8ClampedArray;
  width: number;
  height: number;
};

export type DiffResult = {
  pixelDiffPct: number;
  ssim: number;
  width: number;
  height: number;
  diffPixels: number;
  /** PNG-encoded pixelmatch heatmap (red = differing pixel over a dimmed base). */
  heatmapPng: Buffer;
};

function toRgba(png: PNG): RgbaImage {
  return {
    data: new Uint8ClampedArray(png.data.buffer, png.data.byteOffset, png.data.length),
    width: png.width,
    height: png.height,
  };
}

export async function loadPng(path: string): Promise<RgbaImage> {
  return toRgba(PNG.sync.read(await readFile(path)));
}

export function decodePng(buffer: Buffer): RgbaImage {
  return toRgba(PNG.sync.read(buffer));
}

function assertSameSize(a: RgbaImage, b: RgbaImage): void {
  if (a.width !== b.width || a.height !== b.height) {
    throw new Error(
      `Image dimensions differ: ${a.width}x${a.height} vs ${b.width}x${b.height}. ` +
        `The calibrated diff requires same-settings captures; resize upstream before diffing.`,
    );
  }
}

/** SSIM (fast, mean SSIM) between two equal-size RGBA images. */
export function computeSsim(a: RgbaImage, b: RgbaImage): number {
  const result = ssimFn(
    { data: a.data, width: a.width, height: a.height },
    { data: b.data, width: b.width, height: b.height },
    { ssim: "fast" },
  );
  return roundTo(result.mssim, 4);
}

/** Core diff over two in-memory RGBA images. */
export function diffImages(a: RgbaImage, b: RgbaImage): DiffResult {
  assertSameSize(a, b);
  const { width, height } = a;
  const heatmap = new PNG({ width, height });
  const diffPixels = pixelmatch(a.data, b.data, heatmap.data, width, height, {
    threshold: PIXELMATCH_THRESHOLD,
    includeAA: false,
    alpha: 0.3,
    diffColor: [255, 0, 0],
  });
  const pixelDiffPct = roundTo((diffPixels / (width * height)) * 100, 4);
  return {
    pixelDiffPct,
    ssim: computeSsim(a, b),
    width,
    height,
    diffPixels,
    heatmapPng: PNG.sync.write(heatmap),
  };
}

/** Diff two PNG files. Optionally write the heatmap PNG to `heatmapPath`. */
export async function diffFiles(
  refPath: string,
  recPath: string,
  opts: { heatmapPath?: string } = {},
): Promise<DiffResult> {
  const [ref, rec] = await Promise.all([loadPng(refPath), loadPng(recPath)]);
  const result = diffImages(ref, rec);
  if (opts.heatmapPath) {
    await mkdir(dirname(opts.heatmapPath), { recursive: true });
    await writeFile(opts.heatmapPath, result.heatmapPng);
  }
  return result;
}

function roundTo(value: number, places: number): number {
  if (!Number.isFinite(value)) return value;
  const factor = 10 ** places;
  return Math.round(value * factor) / factor;
}
